window.__QUIZ_DATA__=[{"id":"theory>Geography>2024 Paper 3>1>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the question that follow    In your answer booklet, draw an outline of the mapped area to a third of its original size and state the scale of the new outline.","images":["data:image/png;base64,"],"marking_scheme":"Original scale: 1cm reps 50,000cm  Hence the new scale:  1cm =n/3cm  1 x n/3=50,000 x 1  n=3 x 50,000=150,000  Hence, the new scale of the map = 1:150,000  Old length = 29.5cm  \u2234New Length = 29.5/3=9.8cm  Old width = 29.5cm  \u2234New width = 29.5/3=9.8cm","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>1>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the question that follow  In your new outline, insert and name:  i. River Nyamsu and its direction of flow with an arrow;  ii the ridge at the south eastern part of the mapped area;  iii Jimisokakraba settlement","images":["data:image/png;base64,"],"marking_scheme":"","marks":"7","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>1>c","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the question that follow  Describe three characteristics of the feature running from South western to the North eastern part of the mapped area.","images":[],"marking_scheme":"-Linear Elevation: It is a long, narrow elevated landform that typically extends for several kilometers, therefore, it is a ridge  -Steep Slopes: The sides of the ridge is made up of steep, forming sharp angles with the adjacent valleys or plains.  -Sparse Vegetation: There is limited plant growth due to poor soil stability.  -Crest: The top of the ridge, known as the crest, is narrow.  -Drainage Pattern: There is fast surface runoff for gullies or stream channels.  -Parallel Formation: It occur in parallel sequences and valleys are aligned in a linear pattern.","marks":"1","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>1>d","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"d","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1:50,000 and answer the question that follow  Describe three ways in which transportation network is influenced by the relief in the mapped area.","images":[],"marking_scheme":"-Roads avoid steep slopes in the entire map.  -The main road is found in the northwestern part of the map where the relief is gently rolling.  -The secondary road avoids hills and ridge at the southern part of the map  -The minor road in the mapped area runs parallel to the rugged relief from the North to south.  -Roads avoid highlands and take advantage of lowlands in the mapped area","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>2>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The Table G below shows the value of commodities exported by a country in the year 2020. Study and use it to answer the questions that follow.  Exported commodities Value of commodities in US dollarsCocoa729Diamond400Gold900Crude Oil196    Using a radius scale of 1cm to represent 10 units, draw proportional circles to represent the value of exported commodities by the country in the year 2020. [Use the square root method]","images":[],"marking_scheme":"Calculate the total value of exported commodities  Total value = 729 + 400 + 900  Total value = 2225(in US dollars)  Draw proportion circles using the square root method   Radius for Cocoa:  \u221a729/10=\u221a72.9 =8.53cm  Radius for Diamond:  \u221a400/10=\u221a40=6.32cm  Radius for Gold:  \u221a900/10=\u221a90=9.49cm  Radius for Crude Oil:  \u221a196/10=\u221a19.6=4.43cm","marks":"13","difficulty":"3"},{"id":"theory>Geography>2024 Paper 3>2>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The Table G below shows the value of commodities exported by a country in the year 2020. Study and use it to answer the questions that follow.  Exported commodities Value of commodities in US dollarsCocoa729Diamond400Gold900Crude Oil196Calculate the percentage of the value of gold exported in the year 2020","images":[],"marking_scheme":"Percentage of gold exported= (400/2225) * 100  Percentage of gold exported =18","marks":"2","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>3>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"List three processes of wind erosion","images":[],"marking_scheme":"-Deflation  -Abrasion  -Attrition","marks":"3","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>3>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"With the aid of a diagram, describe the characteristics and mode of formation of a zeugen","images":["data:image/png;base64,"],"marking_scheme":"Structure showing the characteristics and mode of formation of a Zeugen.","marks":"12","difficulty":"3"},{"id":"theory>Geography>2024 Paper 3>4>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"What is an igneous rock?","images":[],"marking_scheme":"An igneous rock is a type of rock that forms from the cooling and solidification of molten rock material, either magma beneath the Earth's surface or lava on the surface. Examples include granite and basalt.    OR    An Igneous rock is a rock that is formed as a result of hot molten magma escaping to earth surface and cooling. Examples are granite and basalt.    OR    An Igneous rock is a type of rock that crystallizes from molten magma or lava, forming intrusive or extrusive structures based on where it cools. Examples: granite and basalt.","marks":"2","difficulty":"1"},{"id":"theory>Geography>2024 Paper 3>4>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"State three characteristics of igneous rocks","images":[],"marking_scheme":"-Igneous rocks typically have a crystalline texture, where the minerals form interlocking crystals.  -They are composed of various minerals such as quartz, feldspar, mica, etc.  -Igneous rocks are generally hard and durable due to the strong bonding between their mineral components.  -Igneous rocks do not contain fossils because they form from molten material, which destroys any organic matter.  -They can have a wide range of chemical compositions, from felsic (rich in silica) to mafic (rich in magnesium and iron).","marks":"3","difficulty":"1"},{"id":"theory>Geography>2024 Paper 3>4>c","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Explain five economic importance of igneous rocks","images":[],"marking_scheme":"-Construction Material: Igneous rocks like granite and basalt are extensively used as construction materials for buildings, roads, and monuments due to their strength and durability.  -Mining Resources: Igneous rocks are rich in minerals and ores. For example, they are a major source of metals like gold, silver, copper, and iron.  -Gemstones: Certain igneous rocks are sources of valuable gemstones, such as diamonds found in kimberlite pipes.  -Soil Fertility: The weathering of igneous rocks contributes to soil formation, providing essential minerals that enhance soil fertility for agriculture.  -Industrial Use: Some igneous rocks are used in various industrial applications. For instance, pumice is used as an abrasive material, and perlite is used in the production of lightweight aggregates for concrete and plaster.  -Geothermal Energy: Areas with igneous activity are often rich in geothermal energy, which can be harnessed for electricity production and heating.  -Tourism: Igneous rock formations and volcanic landscapes attract tourists, contributing to the economy through tourism and related services.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>5>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"State three conditions that favour the development of Karst topography","images":[],"marking_scheme":"-Soluble rocks (limestone, dolomite, gypsum)  -High rainfall and precipitation  -Low relief and gentle slopes  -Good drainage and permeable rocks  -Tectonic stability and minimal faulting","marks":"3","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>5>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe the characteristics and mode","images":[],"marking_scheme":"Mode of formation of sink hole:    Sinkholes are depressions or holes in the ground caused by the collapse of a surface layer. They form primarily through chemical weathering, where slightly acidic rainwater dissolves soluble bedrock such as limestone or dolomite. This process creates underground voids and cavities as water seeps through the soil and rock, dissolving more material over time. Sinkholes can form either gradually or suddenly, depending on the type of material and the presence of groundwater.    Characteristics of sink hole:    -They vary from a few meters to hundreds of meters in diameter and depth, typically circular or oval.  -They can be small, shallow depressions or large, deep chasms; may be bare rock, soil, or water-filled.  -They are common in karst landscapes with features like caves and disappearing streams.","marks":"12","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>6>a>i","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"i","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Using Koppen's System of classification of climates, identify the types of climate that are represented by the letters listed below:    Af","images":[],"marking_scheme":"AF: Tropical rainforest climate (high temperature and high rainfall throughout the year)","marks":"1","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>6>a>ii","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Using Koppen's System of classification of climates, identify the types of climate that are represented by the letters listed below:  Am","images":[],"marking_scheme":"Am: Tropical monsoon climate (high temperature and high rainfall, with a dry season)","marks":"1","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>6>a>iii","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"iii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Using Koppen's System of classification of climates, identify the types of climate that are represented by the letters listed below:  Aw","images":[],"marking_scheme":"Aw: Tropical savanna climate (high temperature and moderate rainfall, with a dry season)","marks":"1","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>6>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Outline six characteristics of the Af climate","images":[],"marking_scheme":"-High and Uniform Temperatures: The Af climate maintains high temperatures year-round, with monthly averages typically ranging between 25\u00b0C to 30\u00b0C (77\u00b0F to 86\u00b0F).  -Abundant and Evenly Distributed Rainfall: This climate experiences heavy rainfall throughout the year, with no distinct dry season.  -High Humidity: Due to the high temperatures and consistent rainfall, humidity levels in Af climates are typically very high, often exceeding 80%.  -Dense Vegetation and Biodiversity: The constant warm and wet conditions support dense tropical rainforests with diverse plant and animal life.  -Frequent Cloud Cover: Persistent cloud cover is common due  -Equatorial Location: The Af climate is predominantly found around the equator, between latitudes 10\u00b0N and 10\u00b0S.  -Low fertility soil: Soils in Af climates are often highly weathered and leached, with low fertility due to the intense rainfall washing away nutrients.","marks":"12","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>7>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"List three features that can be found in the middle course of a river","images":[],"marking_scheme":"-Meanders (Bends)  -Riffles  -Pools  -Gravel Bars","marks":"3","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>7>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL PROBLEMS/ HAZARDS","question":"Describe the characteristics and mode of formation of pothole","images":[],"marking_scheme":"-Circular or Elliptical Shape: Potholes are typically round or oval depressions found on the riverbed.    -Varied Sizes: They can range in size from a few centimeters to several meters in diameter and depth.    -Smooth Interior: The interior surfaces of potholes are usually smooth due to continuous abrasion by swirling water and sediment.    MODE OF FORMATION OF POTHOLE:    -Initial Depression: Potholes start forming in areas where there is an initial depression in the riverbed, often due to irregularities in the rock surface    -Swirling Water: During high flow conditions, water starts to swirl in these depressions, creating a circular current.    -Abrasion: Sediments like sand, gravel, and pebbles carried by the river are caught in the swirling current. These sediments act like a natural drill, grinding against the rock surface.    -Deepening and Widening: Over time, the continuous abrasion deepens and widens the depression, forming a pothole    -Maintenance: Potholes are maintained and enlarged by the constant supply of abrasive sediments and the persistent swirling motion of water.","marks":"12","difficulty":"3"},{"id":"theory>Geography>2024 Paper 3>8>a","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Define atmospheric resources","images":[],"marking_scheme":"Atmospheric resources refer to the various components of the Earth's atmosphere that are utilized or harnessed by humans for various purposes. These resources include air for breathing, wind energy for power generation, and atmospheric gases such as oxygen and nitrogen for industrial, agricultural, and scientific applications.    OR    Atmospheric resources could be the collective term for natural elements and phenomena found in the Earth's atmosphere that are valuable or useful to humans. This includes not only the gases that make up the atmosphere, but also phenomena such as weather patterns, atmospheric circulation, and the ozone layer.","marks":"3","difficulty":"1"},{"id":"theory>Geography>2024 Paper 3>8>b","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"b","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Outline three importance of atmospheric resources","images":[],"marking_scheme":"-Air Quality and Human Health: The atmosphere provides the air we breathe, which is essential for human survival.Monitoring and managing atmospheric resources help ensure that the air remains safe for breathing.  -Renewable Energy: The atmosphere contains wind energy, which can be harnessed through wind turbines to generate electricity.Harnessing wind energy contributes to a cleaner and more sustainable energy future.  -Weather Prediction and Disaster Management: Atmospheric resources are crucial for weather prediction and forecasting, which helps communities prepare for and respond to natural disasters such as hurricanes, tornadoes, and droughts  -Ecosystem Support: The atmosphere provides essential resources for terrestrial and aquatic ecosystems. Atmospheric gases such as oxygen and nitrogen are vital for supporting plant and animal life.  -Climate Regulation: Atmospheric resources play a key role in regulating Earth's climate. Gases such as carbon dioxide, methane, and water vapor influence the greenhouse effect, which helps to maintain a stable temperature range suitable for life on Earth.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2024 Paper 3>8>c","subject":"Geography","year":"2024 Paper 3","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Highlight three human activities that adversely affect the composition of the atmosphere","images":[],"marking_scheme":"-Burning Fossil Fuels: Combustion of coal, oil, and natural gas releases carbon dioxide, sulfur dioxide, and other pollutants into the atmosphere, contributing to air pollution and climate change.  -Deforestation: Cutting down trees reduces the number of plants that can absorb carbon dioxide from the atmosphere, leading to increased greenhouse gas levels.  -Industrial Processes: Manufacturing activities release various pollutants, including particulate matter, nitrogen oxides, and volatile organic compounds, which degrade air quality and contribute to global warming.  -Agricultural Practices: Intensive farming methods, such as livestock production and the use of chemical fertilizers and pesticides, release methane and nitrous oxide, potent greenhouse gases, into the atmosphere.  -Waste Management: Improper disposal of waste, including landfilling and open burning, releases methane and other pollutants into the air, contributing to both air pollution and climate change.","marks":"1","difficulty":"2"}];